chrome.runtime.onMessage.addListener((e,o,t)=>{if(e.type==="GET_SETTINGS")return chrome.storage.sync.get(["enabled","mode","customPrompt","voiceId","volume","proxyUrl","authToken"],r=>{t(r)}),!0;if(e.type==="SAVE_SETTINGS")return chrome.storage.sync.set(e.settings,()=>{chrome.tabs.query({},r=>{r.forEach(c=>{chrome.tabs.sendMessage(c.id,{type:"SETTINGS_UPDATED",settings:e.settings}).catch(()=>{})})}),t({success:!0})}),!0;e.type==="PING"&&t({alive:!0})});
